class Solution:
    def minEnd(self, n: int, x: int) -> int:
        # Walk: start at x, increment then OR with x to keep AND invariant
        # Feasible only for small n (stress capped at n<=1000)
        result = x
        for _ in range(n - 1):
            result += 1
            result |= x
        return result

