class Solution:
    def minEnd(self, n: int, x: int) -> int:
        # Spread bits of (n-1) into the 0-bit positions of x
        m = n - 1
        result = x
        bit_pos = 0
        m_bit = 0
        while m_bit < m.bit_length() or (m >> m_bit) > 0:
            # find next 0 bit in x at position bit_pos
            while (x >> bit_pos) & 1:
                bit_pos += 1
            # place bit m_bit of m into position bit_pos of result
            if (m >> m_bit) & 1:
                result |= (1 << bit_pos)
            m_bit += 1
            bit_pos += 1
            if m_bit > 60:
                break
        return result

