var minEnd = function(n, x) {
    let m = n - 1;
    let result = BigInt(x);
    let xb = BigInt(x);
    let bitPos = 0;
    let mBit = 0;
    while (mBit < 64) {
        while ((xb >> BigInt(bitPos)) & 1n) bitPos++;
        if ((BigInt(m) >> BigInt(mBit)) & 1n) {
            result |= (1n << BigInt(bitPos));
        }
        mBit++;
        bitPos++;
        if (mBit > 30 && (BigInt(m) >> BigInt(mBit)) === 0n) break;
    }
    return Number(result);
};
